#!/usr/bin/env node
const fs = require('fs');
const path = require('path');

const PATCH_NAME = "BARNDAKSA_PERFORMANCE_CORE_PATCH";
const FILES = [{"path": "proxy.ts", "data": ""}, {"path": "app/actions/dashboard-shell.ts", "data": ""}, {"path": "components/dashboard/dashboard-app-layout.tsx", "data": ""}, {"path": "components/dashboard/DashboardSidebar.tsx", "data": ""}, {"path": "lib/performance/dashboard-shell-client.ts", "data": ""}, {"path": "lib/performance/server-memory-cache.ts", "data": ""}, {"path": "components/performance/route-prefetcher.tsx", "data": ""}, {"path": "app/layout.tsx", "data": ""}, {"path": "app/api/public/cafe/[slug]/route.ts", "data": ""}, {"path": "app/api/public/cafe/[slug]/menu/route.ts", "data": ""}, {"path": "app/api/public/storage/route.ts", "data": ""}, {"path": "lib/cafe/use-public-cafe-menu.ts", "data": ""}, {"path": "lib/cafe/use-cafe-theme-page.ts", "data": ""}, {"path": "lib/cafe/use-custom-identity-visuals.ts", "data": ""}, {"path": "lib/cafe/use-resolved-cafe-logo.ts", "data": ""}, {"path": "lib/cafe/use-local-asset-url.ts", "data": ""}, {"path": "BARNDAKSA_PERFORMANCE_DB_FAST_PATH.sql", "data": ""}];

function stamp() {
  const d = new Date();
  const pad = (n) => String(n).padStart(2, '0');
  return `${d.getFullYear()}${pad(d.getMonth()+1)}${pad(d.getDate())}_${pad(d.getHours())}${pad(d.getMinutes())}${pad(d.getSeconds())}`;
}

function ensureDir(dir) {
  fs.mkdirSync(dir, { recursive: true });
}

function assertProjectRoot(root) {
  const required = ['package.json', 'app', 'components', 'lib'];
  const missing = required.filter((item) => !fs.existsSync(path.join(root, item)));
  if (missing.length) {
    console.error('❌ شغل السكربت من جذر المشروع E:\branda-platform');
    console.error('المفقود:', missing.join(', '));
    process.exit(1);
  }
}

function writeFile(root, rel, data, backupRoot) {
  const target = path.join(root, rel);
  if (fs.existsSync(target)) {
    const backup = path.join(backupRoot, rel + '.bak');
    ensureDir(path.dirname(backup));
    fs.copyFileSync(target, backup);
  }
  ensureDir(path.dirname(target));
  fs.writeFileSync(target, data);
  console.log('✅', rel);
}

function main() {
  const root = process.cwd();
  assertProjectRoot(root);

  const backupRoot = path.join(root, '.barndaksa-patch-backups', `performance-core-${stamp()}`);
  ensureDir(backupRoot);

  for (const file of FILES) {
    const data = Buffer.from(file.data, 'base64');
    writeFile(root, file.path, data, backupRoot);
  }

  console.log('');
  console.log('✅ تم تطبيق باتش تسريع برندة بنجاح.');
  console.log('📌 تم إنشاء نسخة احتياطية هنا:');
  console.log(backupRoot);
  console.log('');
  console.log('⚠️ مهم: افتح BARNDAKSA_PERFORMANCE_DB_FAST_PATH.sql من جذر المشروع وشغله مرة واحدة في Supabase SQL Editor.');
  console.log('بعدها شغل: npm exec tsc -- --noEmit ثم npm run build');
}

main();
